const source = $node['Build Reddit Prompt'].json;
const raw = String($json.text || '').trim();
function parseJson(text) {
  const fenced = text.match(/\`\`\`(?:json)?\s*([\s\S]*?)\`\`\`/i);
  const body = fenced ? fenced[1] : text;
  const first = body.indexOf('{');
  const last = body.lastIndexOf('}');
  if (first < 0 || last < first) throw new Error('Bonsai Reddit draft was not JSON: ' + text.slice(0, 300));
  return JSON.parse(body.slice(first, last + 1));
}
function finalize(parsed, textKey) {
  const products = source.products || [];
  const product = products.find((p) => p.slug === parsed.selected_product_slug && p.affiliate_url) || null;
  let text = String(parsed[textKey] || '').trim();
  const allowProduct = parsed.affiliate_allowed === true && product && parsed.safety === 'answer' && text.length > 80;
  if (allowProduct && !text.includes(product.affiliate_url)) {
    text += '\n\nHelpful resource: ' + product.name + ' - ' + product.affiliate_url;
    text += '\n' + source.config.default_disclosure;
  }
  return { text, product, affiliateAllowed: Boolean(allowProduct) };
}
const parsed = parseJson(raw);
const final = finalize(parsed, 'reply');
return [{ json: { ...source, redditDraft: { raw, text: final.text, safety: parsed.safety || 'human_review', affiliateAllowed: final.affiliateAllowed, selectedProductSlug: final.product ? final.product.slug : '', selectedProductName: final.product ? final.product.name : '', reason: parsed.reason || '' } } }];

const source = $node['Build Quora Prompt'].json;
const raw = String($json.text || '').trim();
function parseJson(text) {
  const fenced = text.match(/\`\`\`(?:json)?\s*([\s\S]*?)\`\`\`/i);
  const body = fenced ? fenced[1] : text;
  const first = body.indexOf('{');
  const last = body.lastIndexOf('}');
  if (first < 0 || last < first) throw new Error('Bonsai Quora draft was not JSON: ' + text.slice(0, 300));
  return JSON.parse(body.slice(first, last + 1));
}
const parsed = parseJson(raw);
const product = (source.products || []).find((p) => p.slug === parsed.selected_product_slug && p.affiliate_url) || null;
let text = String(parsed.answer || '').trim();
const allowProduct = parsed.affiliate_allowed === true && product && parsed.safety === 'answer' && text.length > 120;
if (allowProduct && !text.includes(product.affiliate_url)) {
  text += '\n\nHelpful resource: ' + product.name + ' - ' + product.affiliate_url;
  text += '\n' + source.config.default_disclosure;
}
return [{ json: { ...source, quoraDraft: { raw, text, safety: parsed.safety || 'human_review', affiliateAllowed: Boolean(allowProduct), selectedProductSlug: product ? product.slug : '', selectedProductName: product ? product.name : '', reason: parsed.reason || '' } } }];

const data = $json;
function clip(text, limit) {
  const value = String(text || '');
  return value.length > limit ? value.slice(0, limit - 3) + '...' : value;
}
const redditMessage = [
  'Sarah Nutri Reddit manual post',
  '',
  'Subreddit: ' + (data.reddit.subreddit ? 'r/' + data.reddit.subreddit : 'unknown'),
  'Question: ' + data.reddit.title,
  'URL: ' + (data.reddit.url || 'manual/source search'),
  'Safety: ' + data.redditDraft.safety,
  'Affiliate: ' + (data.redditDraft.affiliateAllowed ? 'yes - ' + data.redditDraft.selectedProductName : 'no'),
  'Reason: ' + data.redditDraft.reason,
  '',
  'Copy/paste reply:',
  clip(data.redditDraft.text, 1400)
].join('\n');
const quoraMessage = [
  'Sarah Nutri Quora manual post',
  '',
  'Question: ' + data.quora.title,
  'URL: ' + (data.quora.url || 'manual/source search'),
  'Safety: ' + data.quoraDraft.safety,
  'Affiliate: ' + (data.quoraDraft.affiliateAllowed ? 'yes - ' + data.quoraDraft.selectedProductName : 'no'),
  'Reason: ' + data.quoraDraft.reason,
  '',
  'Copy/paste answer:',
  clip(data.quoraDraft.text, 1500)
].join('\n');
return [
  { json: { ok: true, platform: 'reddit', discordMessage: redditMessage, candidate: data.reddit, draft: data.redditDraft } },
  { json: { ok: true, platform: 'quora', discordMessage: quoraMessage, candidate: data.quora, draft: data.quoraDraft } }
];
